#!/bin/bash

# Colors
export RED='\033[0;31m'
export GREEN='\033[0;32m'
export YELLOW='\033[1;33m'
export BLUE='\033[0;34m'
export CYAN='\033[0;36m'
export NC='\033[0m' # No Color

# Logging functions
debug_log() {
    echo -e "${BLUE} $1${NC}"
}

prompt_log() {
    echo -e "${CYAN} $1${NC}"
}

warning_log() {
    echo -e "${YELLOW} $1${NC}"
}

success_log() {
    echo -e "${GREEN}󰗡 $1${NC}"
}

error_log() {
    echo -e "${RED} $1${NC}"
}

get_config() {
    local key=$1
    yq eval "$key" "$(dirname "${BASH_SOURCE[0]}")/config.yml"
}

export -f debug_log
export -f prompt_log
export -f warning_log
export -f success_log
export -f error_log
export -f get_config

arguments.content:
.PHONY: install install-dry-run flash-moonlander flash-crkbd flash-chocofi flash-voyager update-svg update-qmk help

install:
	./koyo setup

install-dry-run:
	./koyo setup --dry-run

flash-moonlander:
	./koyo moonlander flash

flash-crkbd:
	./koyo crkbd flash

flash-chocofi:
	./koyo chocofi flash

flash-voyager:
	./koyo voyager flash

update-svg:
	./koyo update svg

update-qmk:
	./koyo update qmk

help:
	@echo "make install              Setup koyo on a new machine"
	@echo "make install-dry-run      Preview setup without changes"
	@echo "make flash-moonlander     Flash Moonlander keyboard"
	@echo "make flash-crkbd          Flash Corne keyboard"
	@echo "make flash-chocofi        Flash Chocofi keyboard"
	@echo "make flash-voyager        Flash Voyager keyboard"
	@echo "make update-svg           Regenerate layout SVG"
	@echo "make update-qmk           Update QMK firmware to latest master"
